HEADERS = ["Active","Client Name","Website URL","Google Drive Folder","GitHub Dashboard","GSC Connected","GA4 Connected","GMB Connected","Blog: Who Writes","Blog: Who Publishes","Content Approval","On-Page Audits/Month","Citation Links/Month","Guest Posting","Tech Audit Cycle","Platforms (Reddit/Quora/Medium)","New Pages This Month","PowerSuite Project Name","Primary Contact","Contact Email","Contract Start","Assigned Team Member","Notes"]

def get_credentials():
    with open('token.pickle', 'rb') as token:
        creds = pickle.load(token)
    if creds and creds.expired and creds.refresh_token:
        creds.refresh(Request())
    return creds

def fix_profile():
    creds = get_credentials()
    gc = gspread.authorize(creds)
    sh = gc.open_by_key(SHEET_ID)
    ws = sh.worksheet("01_Client Profile")

    # Clear everything from row 1 onwards
    ws.clear()

    # Row 1: Title
    ws.update("A1", [["  ThirdSlash | Client Profile"]])

    # Row 2: Subtitle
    ws.update("A2", [["  One row per client — configuration master"]])

    # Row 3: Headers
    ws.update("A3", [HEADERS])

    # Rows 4 onwards: Client data
    rows = [[c.get(h, "") for h in HEADERS] for c in CLIENTS]
    ws.append_rows(rows)

    print(f"Fixed. {len(CLIENTS)} clients written cleanly to 01_Client Profile.")
    for c in CLIENTS:
        print(f"  + {c['Client Name']} | Active: {c['Active']} | {c['Assigned Team Member']}")

fix_profile()
